var metadata31 = {
  title: "Chande Momentum Oscillator",
  shortTitle: "ChandeMO",
  overlay: false
};
function calculate31(bars, inputs = {}) {
  const { length } = { ...defaultInputs31, ...inputs };
  const close = bars.map((b) => b.close);
  const mom = [NaN];
  for (let i = 1; i < bars.length; i++) {
    mom.push(close[i] - close[i - 1]);
  }
  const m1 = mom.map((m) => m >= 0 ? m : 0);
  const m2 = mom.map((m) => m >= 0 ? 0 : -m);
  const chandeMO = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < length) {
      chandeMO.push(NaN);
      continue;
    }
    let sm1 = 0;
    let sm2 = 0;
    for (let j = i - length + 1; j <= i; j++) {
      if (!isNaN(m1[j]))
        sm1 += m1[j];
      if (!isNaN(m2[j]))
        sm2 += m2[j];
    }
    const sum = sm1 + sm2;
    if (sum === 0) {
      chandeMO.push(0);
    } else {
      chandeMO.push(100 * (sm1 - sm2) / sum);
    }
  }
  const cmoData = chandeMO.map((value, i) => ({
    time: bars[i].time,
    value: value ?? NaN
  }));
  return {
    metadata: {
      title: metadata31.title,
      shorttitle: metadata31.shortTitle,
      overlay: metadata31.overlay
    },
    plots: {
      "plot0": cmoData
    }
  };
}
