var metadata37 = {
  title: "Money Flow Index",
  shortTitle: "MFI",
  overlay: false
};
function calculate37(bars, inputs = {}) {
  const { length } = { ...defaultInputs37, ...inputs };
  const typicalPrice = bars.map((b) => (b.high + b.low + b.close) / 3);
  const rawMoneyFlow = typicalPrice.map((tp, i) => tp * (bars[i].volume ?? 0));
  const mfiValues = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < length) {
      mfiValues.push(NaN);
      continue;
    }
    let positiveFlow = 0;
    let negativeFlow = 0;
    for (let j = i - length + 1; j <= i; j++) {
      if (j === 0)
        continue;
      if (typicalPrice[j] > typicalPrice[j - 1]) {
        positiveFlow += rawMoneyFlow[j];
      } else if (typicalPrice[j] < typicalPrice[j - 1]) {
        negativeFlow += rawMoneyFlow[j];
      }
    }
    if (negativeFlow === 0) {
      mfiValues.push(100);
    } else {
      const moneyFlowRatio = positiveFlow / negativeFlow;
      const mfi = 100 - 100 / (1 + moneyFlowRatio);
      mfiValues.push(mfi);
    }
  }
  const mfiData = mfiValues.map((value, i) => ({
    time: bars[i].time,
    value: value ?? NaN
  }));
  return {
    metadata: {
      title: metadata37.title,
      shorttitle: metadata37.shortTitle,
      overlay: metadata37.overlay
    },
    plots: {
      "plot0": mfiData
    }
  };
}
