function cci(typicalPrice, length) {
  const result = [];
  for (let i = 0; i < typicalPrice.length; i++) {
    if (i < length - 1) {
      result.push(NaN);
      continue;
    }
    let sum = 0;
    for (let j = i - length + 1; j <= i; j++) {
      sum += typicalPrice[j];
    }
    const sma3 = sum / length;
    let devSum = 0;
    for (let j = i - length + 1; j <= i; j++) {
      devSum += Math.abs(typicalPrice[j] - sma3);
    }
    const meanDev = devSum / length;
    if (meanDev === 0) {
      result.push(0);
    } else {
      result.push((typicalPrice[i] - sma3) / (0.015 * meanDev));
    }
  }
  return result;
}
