var metadata53 = {
  title: "Bollinger BandWidth",
  shortTitle: "BBW",
  overlay: false
};
function calculate53(bars, inputs = {}) {
  const { length, src, mult, expansionLength, contractionLength } = { ...defaultInputs53, ...inputs };
  const source = getSourceSeries(bars, src);
  const basis = ta_series_exports.sma(source, length);
  const dev = ta_series_exports.stdev(source, length).mul(mult);
  const upper = basis.add(dev);
  const lower = basis.sub(dev);
  const basisArr = basis.toArray();
  const upperArr = upper.toArray();
  const lowerArr = lower.toArray();
  const bbw = [];
  for (let i = 0; i < bars.length; i++) {
    const u = upperArr[i];
    const l = lowerArr[i];
    const b = basisArr[i];
    if (u == null || l == null || b == null || b === 0) {
      bbw.push(NaN);
    } else {
      bbw.push((u - l) / b * 100);
    }
  }
  const highestExpansion = [];
  const lowestContraction = [];
  for (let i = 0; i < bars.length; i++) {
    let highest2 = -Infinity;
    for (let j = Math.max(0, i - expansionLength + 1); j <= i; j++) {
      if (!isNaN(bbw[j]) && bbw[j] > highest2)
        highest2 = bbw[j];
    }
    highestExpansion.push(highest2 === -Infinity ? NaN : highest2);
    let lowest = Infinity;
    for (let j = Math.max(0, i - contractionLength + 1); j <= i; j++) {
      if (!isNaN(bbw[j]) && bbw[j] < lowest)
        lowest = bbw[j];
    }
    lowestContraction.push(lowest === Infinity ? NaN : lowest);
  }
  const bbwData = bbw.map((value, i) => ({ time: bars[i].time, value }));
  const highData = highestExpansion.map((value, i) => ({ time: bars[i].time, value }));
  const lowData = lowestContraction.map((value, i) => ({ time: bars[i].time, value }));
  return {
    metadata: {
      title: metadata53.title,
      shorttitle: metadata53.shortTitle,
      overlay: metadata53.overlay
    },
    plots: {
      "plot0": bbwData,
      "plot1": highData,
      "plot2": lowData
    }
  };
}
