function calculate54(bars, inputs = {}) {
  const { length } = { ...defaultInputs54, ...inputs };
  const ad = [];
  const vol = [];
  for (let i = 0; i < bars.length; i++) {
    const { high, low, close, volume } = bars[i];
    const v = volume ?? 0;
    vol.push(v);
    if (close === high && close === low || high === low) {
      ad.push(0);
    } else {
      ad.push((2 * close - low - high) / (high - low) * v);
    }
  }
  const cmf = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < length - 1) {
      cmf.push(NaN);
      continue;
    }
    let sumAD = 0;
    let sumVol = 0;
    for (let j = i - length + 1; j <= i; j++) {
      sumAD += ad[j];
      sumVol += vol[j];
    }
    if (sumVol === 0) {
      cmf.push(0);
    } else {
      cmf.push(sumAD / sumVol);
    }
  }
  const plotData = cmf.map((value, i) => ({
    time: bars[i].time,
    value
  }));
  return {
    metadata: {
      title: metadata54.title,
      shorttitle: metadata54.shortTitle,
      overlay: metadata54.overlay
    },
    plots: {
      "plot0": plotData
    }
  };
}
