function calculate56(bars, inputs = {}) {
  const { shortLength, longLength, signalLength, src, exponential } = { ...defaultInputs56, ...inputs };
  const source = getSourceSeries(bars, src);
  const shortMA = exponential ? ta_series_exports.ema(source, shortLength) : ta_series_exports.sma(source, shortLength);
  const longMA = exponential ? ta_series_exports.ema(source, longLength) : ta_series_exports.sma(source, longLength);
  const shortArr = shortMA.toArray();
  const longArr = longMA.toArray();
  const ppo = [];
  for (let i = 0; i < bars.length; i++) {
    const s = shortArr[i];
    const l = longArr[i];
    if (s == null || l == null || l === 0) {
      ppo.push(NaN);
    } else {
      ppo.push((s - l) / l * 100);
    }
  }
  const ppoSeries = new Series(bars, (_, i) => ppo[i]);
  const signalSeries = exponential ? ta_series_exports.ema(ppoSeries, signalLength) : ta_series_exports.sma(ppoSeries, signalLength);
  const signalArr = signalSeries.toArray();
  const histogram = [];
  for (let i = 0; i < bars.length; i++) {
    const p = ppo[i];
    const s = signalArr[i];
    if (isNaN(p) || s == null) {
      histogram.push(NaN);
    } else {
      histogram.push(p - s);
    }
  }
  const histData = histogram.map((value, i) => {
    const prev = i > 0 ? histogram[i - 1] : NaN;
    let color;
    if (value >= 0) {
      color = prev < value ? "#26A69A" : "#B2DFDB";
    } else {
      color = prev < value ? "#FFCDD2" : "#FF5252";
    }
    return { time: bars[i].time, value, color };
  });
  const ppoData = ppo.map((value, i) => ({ time: bars[i].time, value }));
  const signalData = signalArr.map((value, i) => ({ time: bars[i].time, value: value ?? NaN }));
  return {
    metadata: {
      title: metadata56.title,
      shorttitle: metadata56.shortTitle,
      overlay: metadata56.overlay
    },
    plots: {
      "plot0": histData,
      "plot1": ppoData,
      "plot2": signalData
    }
  };
}
