var metadata59 = {
  title: "Choppiness Index",
  shortTitle: "CHOP",
  overlay: false
};
function calculate59(bars, inputs = {}) {
  const { length } = { ...defaultInputs59, ...inputs };
  const atr1 = ta_series_exports.atr(bars, 1);
  const atr1Arr = atr1.toArray();
  const high = new Series(bars, (b) => b.high);
  const low = new Series(bars, (b) => b.low);
  const highest2 = ta_series_exports.highest(high, length);
  const lowest = ta_series_exports.lowest(low, length);
  const highestArr = highest2.toArray();
  const lowestArr = lowest.toArray();
  const chop = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < length - 1) {
      chop.push(NaN);
      continue;
    }
    let sumATR = 0;
    for (let j = i - length + 1; j <= i; j++) {
      const atrVal = atr1Arr[j];
      if (atrVal != null && !isNaN(atrVal)) {
        sumATR += atrVal;
      }
    }
    const h = highestArr[i];
    const l = lowestArr[i];
    if (h == null || l == null || h === l) {
      chop.push(NaN);
    } else {
      const range = h - l;
      const ci = 100 * Math.log10(sumATR / range) / Math.log10(length);
      chop.push(ci);
    }
  }
  const plotData = chop.map((value, i) => ({
    time: bars[i].time,
    value
  }));
  return {
    metadata: {
      title: metadata59.title,
      shorttitle: metadata59.shortTitle,
      overlay: metadata59.overlay
    },
    plots: {
      "plot0": plotData
    }
  };
}
