var metadata64 = {
  title: "Fisher Transform",
  shortTitle: "Fisher",
  overlay: false
};
function calculate64(bars, inputs = {}) {
  const { length } = { ...defaultInputs64, ...inputs };
  const fisher = [];
  const trigger = [];
  let value = 0;
  let fish1 = 0;
  for (let i = 0; i < bars.length; i++) {
    const bar = bars[i];
    const hl2 = (bar.high + bar.low) / 2;
    let highestHl2 = hl2;
    let lowestHl2 = hl2;
    const lookback = Math.min(i + 1, length);
    for (let j = 0; j < lookback; j++) {
      const prevBar = bars[i - j];
      const prevHl2 = (prevBar.high + prevBar.low) / 2;
      if (prevHl2 > highestHl2)
        highestHl2 = prevHl2;
      if (prevHl2 < lowestHl2)
        lowestHl2 = prevHl2;
    }
    const range = highestHl2 - lowestHl2;
    const normalized = range !== 0 ? (hl2 - lowestHl2) / range - 0.5 : 0;
    const rawValue = 0.66 * normalized + 0.67 * value;
    value = rawValue > 0.99 ? 0.999 : rawValue < -0.99 ? -0.999 : rawValue;
    const prevFish1 = fish1;
    fish1 = 0.5 * Math.log((1 + value) / (1 - value)) + 0.5 * prevFish1;
    fisher.push(fish1);
    trigger.push(prevFish1);
  }
  const plotData0 = fisher.map((value2, i) => ({
    time: bars[i].time,
    value: i < length - 1 ? NaN : value2
  }));
  const plotData1 = trigger.map((value2, i) => ({
    time: bars[i].time,
    value: i < length ? NaN : value2
  }));
  return {
    metadata: {
      title: metadata64.title,
      shorttitle: metadata64.shortTitle,
      overlay: metadata64.overlay
    },
    plots: {
      "plot0": plotData0,
      "plot1": plotData1
    }
  };
}
