var metadata66 = {
  title: "Directional Movement Index",
  shortTitle: "DMI",
  overlay: false
};
function calculate66(bars, inputs = {}) {
  const { adxSmoothing, diLength } = { ...defaultInputs66, ...inputs };
  const high = Series.fromBars(bars, "high");
  const low = Series.fromBars(bars, "low");
  const up = ta_series_exports.change(high, 1);
  const upArr = up.toArray();
  const downArr = ta_series_exports.change(low, 1).toArray().map((v) => v !== null ? -v : null);
  const plusDM = [];
  const minusDM = [];
  for (let i = 0; i < bars.length; i++) {
    const upVal = upArr[i];
    const downVal = downArr[i];
    if (upVal === null) {
      plusDM.push(null);
    } else if (upVal > (downVal ?? 0) && upVal > 0) {
      plusDM.push(upVal);
    } else {
      plusDM.push(0);
    }
    if (downVal === null) {
      minusDM.push(null);
    } else if (downVal > (upVal ?? 0) && downVal > 0) {
      minusDM.push(downVal);
    } else {
      minusDM.push(0);
    }
  }
  const trueRange = ta_series_exports.tr(bars, true);
  const trur = ta_series_exports.rma(trueRange, diLength);
  const trurArr = trur.toArray();
  const plusDMSeries = new Series(bars, (_, i) => plusDM[i] ?? NaN);
  const minusDMSeries = new Series(bars, (_, i) => minusDM[i] ?? NaN);
  const smoothedPlusDMArr = ta_series_exports.rma(plusDMSeries, diLength).toArray();
  const smoothedMinusDMArr = ta_series_exports.rma(minusDMSeries, diLength).toArray();
  const plusDI = [];
  const minusDI = [];
  let lastValidPlus = 0;
  let lastValidMinus = 0;
  for (let i = 0; i < bars.length; i++) {
    const tr = trurArr[i];
    const pDM = smoothedPlusDMArr[i];
    const mDM = smoothedMinusDMArr[i];
    if (tr === null || tr === 0 || pDM === null) {
      plusDI.push(lastValidPlus);
    } else {
      const val = 100 * pDM / tr;
      plusDI.push(val);
      lastValidPlus = val;
    }
    if (tr === null || tr === 0 || mDM === null) {
      minusDI.push(lastValidMinus);
    } else {
      const val = 100 * mDM / tr;
      minusDI.push(val);
      lastValidMinus = val;
    }
  }
  const dx = [];
  for (let i = 0; i < bars.length; i++) {
    const pdi = plusDI[i];
    const mdi = minusDI[i];
    const sum = pdi + mdi;
    dx.push(sum === 0 ? 0 : 100 * Math.abs(pdi - mdi) / sum);
  }
  const dxSeries = new Series(bars, (_, i) => dx[i]);
  const adx = ta_series_exports.rma(dxSeries, adxSmoothing);
  const adxArr = adx.toArray();
  const plotData0 = adxArr.map((value, i) => ({
    time: bars[i].time,
    value: value ?? NaN
  }));
  const plotData1 = plusDI.map((value, i) => ({
    time: bars[i].time,
    value
  }));
  const plotData2 = minusDI.map((value, i) => ({
    time: bars[i].time,
    value
  }));
  return {
    metadata: {
      title: metadata66.title,
      shorttitle: metadata66.shortTitle,
      overlay: metadata66.overlay
    },
    plots: {
      "plot0": plotData0,
      "plot1": plotData1,
      "plot2": plotData2
    }
  };
}
