function calculate91(bars, inputs = {}) {
  const { period, signal } = { ...defaultInputs91, ...inputs };
  const kArr = [];
  const dArr = [];
  const jArr = [];
  let pK = 0;
  let pD = 0;
  for (let i = 0; i < bars.length; i++) {
    const c = bars[i].close;
    let hh = bars[i].high;
    let ll = bars[i].low;
    const lookback = Math.min(i + 1, period);
    for (let j = 0; j < lookback; j++) {
      const b = bars[i - j];
      if (b.high > hh)
        hh = b.high;
      if (b.low < ll)
        ll = b.low;
    }
    const rsv = hh !== ll ? 100 * (c - ll) / (hh - ll) : 0;
    pK = (rsv + (signal - 1) * pK) / signal;
    pD = (pK + (signal - 1) * pD) / signal;
    const pJ = 3 * pK - 2 * pD;
    kArr.push(pK);
    dArr.push(pD);
    jArr.push(pJ);
  }
  const warmup = period - 1;
  const toPlot = (arr) => arr.map((value, i) => ({ time: bars[i].time, value: i < warmup ? NaN : value }));
  const bgColors = [];
  for (let i = warmup; i < bars.length; i++) {
    bgColors.push({
      time: bars[i].time,
      color: jArr[i] > dArr[i] ? "rgba(0,128,0,0.3)" : "rgba(255,0,0,0.3)"
    });
  }
  return {
    metadata: { title: metadata91.title, shorttitle: metadata91.shortTitle, overlay: metadata91.overlay },
    plots: { "plot0": toPlot(kArr), "plot1": toPlot(dArr), "plot2": toPlot(jArr) },
    bgColors
  };
}
