  const sma3 = ta_series_exports.sma(source, length);
  const stdev2 = ta_series_exports.stdev(source, length);
  const smaArr = sma3.toArray();
  const stdevArr = stdev2.toArray();
  const sourceArr = source.toArray();
  const bullArr = new Array(n);
  const bearArr = new Array(n);
