function calculate129(bars, inputs = {}) {
  const { alpha, colorBars } = { ...defaultInputs129, ...inputs };
  const n = bars.length;
  const a = alpha;
  const srcArr = getSourceSeries(bars, "hl2").toArray();
  const it = new Array(n);
  for (let i = 0; i < n; i++) {
    const s0 = srcArr[i] ?? 0;
    const s1 = i > 0 ? srcArr[i - 1] ?? 0 : s0;
    const s2 = i > 1 ? srcArr[i - 2] ?? 0 : s0;
    if (i < 7) {
      it[i] = (s0 + 2 * s1 + s2) / 4;
    } else {
      it[i] = (a - a * a / 4) * s0 + 0.5 * a * a * s1 - (a - 0.75 * a * a) * s2 + 2 * (1 - a) * it[i - 1] - (1 - a) * (1 - a) * it[i - 2];
    }
  }
  const warmup = 7;
  const barColors = [];
  const lagPlot = it.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const lag = 2 * v - (i >= 2 ? it[i - 2] : v);
    const bullish = lag > v;
    const color = bullish ? "#26A69A" : "#EF5350";
    if (colorBars)
      barColors.push({ time: bars[i].time, color });
    return { time: bars[i].time, value: lag, color };
  });
  const itPlot = it.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const lag = 2 * v - (i >= 2 ? it[i - 2] : v);
    const color = lag > v ? "#26A69A" : "#EF5350";
    return { time: bars[i].time, value: v, color };
  });
  const fillColors = bars.map((_, i) => {
    if (i < warmup)
      return "transparent";
    const lag = 2 * it[i] - (i >= 2 ? it[i - 2] : it[i]);
    return lag > it[i] ? "rgba(0,128,0,0.15)" : "rgba(255,0,0,0.15)";
  });
  return {
    metadata: { title: metadata129.title, shorttitle: metadata129.shortTitle, overlay: metadata129.overlay },
    plots: { "plot0": lagPlot, "plot1": itPlot },
    fills: [
      { plot1: "plot0", plot2: "plot1", options: { color: "rgba(0,128,0,0.15)" }, colors: fillColors }
    ],
    barColors
  };
}
