var metadata130 = {
  title: "Price Momentum Oscillator",
  shortTitle: "PMO",
  overlay: false
};
function calculate130(bars, inputs = {}) {
  const { firstLength, secondLength, signalLength } = { ...defaultInputs130, ...inputs };
  const n = bars.length;
  const alpha1 = 2 / firstLength;
  const alpha2 = 2 / secondLength;
  const alpha3 = 2 / signalLength;
  const rocMA = new Array(n);
  const pmo = new Array(n);
  const signal = new Array(n);
  for (let i = 0; i < n; i++) {
    const roc = i > 0 && bars[i - 1].close !== 0 ? (bars[i].close - bars[i - 1].close) / bars[i - 1].close * 100 : 0;
    rocMA[i] = i === 0 ? roc : rocMA[i - 1] + (roc - rocMA[i - 1]) * alpha1;
    const rocMA10 = 10 * rocMA[i];
    pmo[i] = i === 0 ? rocMA10 : pmo[i - 1] + (rocMA10 - pmo[i - 1]) * alpha2;
    signal[i] = i === 0 ? pmo[i] : signal[i - 1] + (pmo[i] - signal[i - 1]) * alpha3;
  }
  const warmup = firstLength;
  const toPlot = (arr) => arr.map((v, i) => ({ time: bars[i].time, value: i < warmup ? NaN : v }));
  const histo = pmo.map((v, i) => {
    const d = v - signal[i];
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const dPrev = i > 0 ? pmo[i - 1] - signal[i - 1] : 0;
    let color;
    if (d > 0) {
      color = d > dPrev ? "#00E676" : "#26A69A";
    } else {
      color = d < dPrev ? "#EF5350" : "#FF9800";
    }
    return { time: bars[i].time, value: d, color };
  });
  const fillColors = [];
  for (let i = 0; i < n; i++) {
    if (i < warmup) {
      fillColors.push("rgba(0,0,0,0)");
    } else {
      fillColors.push(pmo[i] > signal[i] ? "rgba(38,166,154,0.2)" : "rgba(239,83,80,0.2)");
    }
  }
  const barColors = [];
  for (let i = warmup; i < n; i++) {
    const d = pmo[i] - signal[i];
    const dPrev = i > 0 ? pmo[i - 1] - signal[i - 1] : 0;
    let color;
    if (d > 0) {
      color = d > dPrev ? "#00E676" : "#26A69A";
    } else {
      color = d < dPrev ? "#EF5350" : "#FF9800";
    }
    barColors.push({ time: bars[i].time, color });
  }
  return {
    metadata: { title: metadata130.title, shorttitle: metadata130.shortTitle, overlay: metadata130.overlay },
    plots: { "plot0": toPlot(pmo), "plot1": toPlot(signal), "plot2": histo },
    fills: [{ plot1: "plot0", plot2: "plot1", options: { color: "rgba(38,166,154,0.2)" }, colors: fillColors }],
    hlines: [
      { value: 0, options: { color: "#787B86", linestyle: "dotted", title: "Zero" } },
      { value: 2.5, options: { color: "#787B86", linestyle: "dashed", title: "OB Level" } },
      { value: -2.5, options: { color: "#787B86", linestyle: "dashed", title: "OS Level" } }
    ],
    barColors
  };
}
