var metadata131 = {
  title: "Fibonacci Bollinger Bands",
  shortTitle: "FBB",
  overlay: true
};
function calculate131(bars, inputs = {}) {
  const { length, mult } = { ...defaultInputs131, ...inputs };
  const src = getSourceSeries(bars, "hlc3");
  const vol = new Series(bars, (b) => b.volume ?? 1);
  const srcVol = src.mul(vol);
  const smaVol = ta_series_exports.sma(vol, length);
  const smaSrcVol = ta_series_exports.sma(srcVol, length);
  const basisArr = smaSrcVol.div(smaVol).toArray();
  const dev = ta_series_exports.stdev(src, length).toArray();
  const fibs = [0.236, 0.382, 0.5, 0.618, 0.764, 1];
  const warmup = length;
  const makePlot = (fn) => bars.map((bar, i) => {
    if (i < warmup || basisArr[i] == null || dev[i] == null)
      return { time: bar.time, value: NaN };
    return { time: bar.time, value: fn(basisArr[i], dev[i]) };
  });
  const plots = {
    "plot0": makePlot((b) => b)
  };
  fibs.forEach((f, idx) => {
    plots[`plot${1 + idx * 2}`] = makePlot((b, d) => b + f * mult * d);
    plots[`plot${2 + idx * 2}`] = makePlot((b, d) => b - f * mult * d);
  });
  return {
    metadata: { title: metadata131.title, shorttitle: metadata131.shortTitle, overlay: metadata131.overlay },
    plots
  };
}
