var metadata132 = {
  title: "Trend Trigger Factor",
  shortTitle: "TTF",
  overlay: false
};
function calculate132(bars, inputs = {}) {
  const { length, buyTrigger, sellTrigger } = { ...defaultInputs132, ...inputs };
  const n = bars.length;
  const highSeries = new Series(bars, (b) => b.high);
  const lowSeries = new Series(bars, (b) => b.low);
  const hhArr = ta_series_exports.highest(highSeries, length).toArray();
  const llArr = ta_series_exports.lowest(lowSeries, length).toArray();
  const warmup = 2 * length;
  const ttfArr = new Array(n);
  for (let i = 0; i < n; i++) {
    if (i < warmup) {
      ttfArr[i] = NaN;
      continue;
    }
    const hh = hhArr[i] ?? 0;
    const ll = llArr[i] ?? 0;
    const hhPrev = hhArr[i - length] ?? 0;
    const llPrev = llArr[i - length] ?? 0;
    const bp = hh - llPrev;
    const sp = hhPrev - ll;
    const denom = 0.5 * (bp + sp);
    ttfArr[i] = denom !== 0 ? 100 * (bp - sp) / denom : 0;
  }
  const ttfPlot = ttfArr.map((v, i) => ({
    time: bars[i].time,
    value: isNaN(v) ? NaN : v
  }));
  const bsPlot = ttfArr.map((v, i) => ({
    time: bars[i].time,
    value: isNaN(v) ? NaN : v > buyTrigger ? buyTrigger : v
  }));
  const usPlot = ttfArr.map((v, i) => ({
    time: bars[i].time,
    value: isNaN(v) ? NaN : v < sellTrigger ? sellTrigger : v
  }));
  return {
    metadata: { title: metadata132.title, shorttitle: metadata132.shortTitle, overlay: metadata132.overlay },
    plots: { "plot0": ttfPlot, "plot1": bsPlot, "plot2": usPlot },
    fills: [
      { plot1: "plot1", plot2: "plot0", options: { color: "rgba(0,128,0,0.25)" } },
      { plot1: "plot2", plot2: "plot0", options: { color: "rgba(255,0,0,0.25)" } }
    ],
    hlines: [
      { value: buyTrigger, options: { color: "#787B86", linestyle: "dashed", title: "Buy" } },
      { value: 0, options: { color: "#787B86", linestyle: "dotted", title: "Zero" } },
      { value: sellTrigger, options: { color: "#787B86", linestyle: "dashed", title: "Sell" } }
    ]
  };
}
