  const v2MfiArr = ta_series_exports.wma(new Series(bars, (_b, i) => v1Mfi[i]), wmaLength).toArray();
  const warmup = Math.max(stochLength, rsiLength, cciLength, mfiLength) + wmaLength;
  const plot0Data = [];
