function calculate144(bars, inputs = {}) {
  const { length, src } = { ...defaultInputs144, ...inputs };
  const sourceArr = getSourceSeries(bars, src).toArray();
  const k = 2 / (length + 1);
  const invLen = 1 / length;
  const vmaArr = new Array(bars.length);
  let pdmS = 0;
  let mdmS = 0;
  let prevVMA = 0;
  for (let i = 0; i < bars.length; i++) {
    const s = sourceArr[i] ?? 0;
    const sPrev = i > 0 ? sourceArr[i - 1] ?? 0 : s;
    const pdm = Math.max(s - sPrev, 0);
    const mdm = Math.max(sPrev - s, 0);
    if (i === 0) {
      pdmS = pdm;
      mdmS = mdm;
      prevVMA = s;
      vmaArr[i] = s;
      continue;
    }
    pdmS = pdmS * (1 - invLen) + pdm * invLen;
    mdmS = mdmS * (1 - invLen) + mdm * invLen;
    const sumDM = pdmS + mdmS;
    const pdi = sumDM !== 0 ? pdmS / sumDM : 0;
    const mdi = sumDM !== 0 ? mdmS / sumDM : 0;
    const sumDI = pdi + mdi;
    const vI = sumDI !== 0 ? Math.abs(pdi - mdi) / sumDI : 0;
    const vma = k * vI * s + (1 - k * vI) * prevVMA;
    vmaArr[i] = vma;
    prevVMA = vma;
  }
  const warmup = length * 3;
  const plot0 = vmaArr.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const prev = vmaArr[i - 1];
    let color;
    if (v > prev)
      color = "#26A69A";
    else if (v < prev)
      color = "#EF5350";
    else
      color = "#9C27B0";
    return { time: bars[i].time, value: v, color };
  });
  const barColors = [];
  for (let i = warmup; i < bars.length; i++) {
    const v = vmaArr[i];
    const prev = vmaArr[i - 1];
    if (v > prev)
      barColors.push({ time: bars[i].time, color: "#26A69A" });
    else if (v < prev)
      barColors.push({ time: bars[i].time, color: "#EF5350" });
    else
      barColors.push({ time: bars[i].time, color: "#2196F3" });
  }
  return {
    metadata: { title: metadata144.title, shorttitle: metadata144.shortTitle, overlay: metadata144.overlay },
    plots: { "plot0": plot0 },
    barColors
  };
}
