var metadata156 = {
  title: "ADX by cobra",
  shortTitle: "ADX Cobra",
  overlay: false
};
function calculate156(bars, inputs = {}) {
  const { adxLen } = { ...defaultInputs156, ...inputs };
  const n = bars.length;
  const diPlusArr = new Array(n);
  const diMinusArr = new Array(n);
  const adxArr = new Array(n);
  let smoothTR = 0;
  let smoothPlusDM = 0;
  let smoothMinusDM = 0;
  let adx = 0;
  for (let i = 0; i < n; i++) {
    const high = bars[i].high;
    const low = bars[i].low;
    const prevHigh = i > 0 ? bars[i - 1].high : high;
    const prevLow = i > 0 ? bars[i - 1].low : low;
    const prevClose = i > 0 ? bars[i - 1].close : bars[i].close;
    const tr = Math.max(high - low, Math.abs(high - prevClose), Math.abs(low - prevClose));
    const upMove = high - prevHigh;
    const downMove = prevLow - low;
    const plusDM = upMove > downMove && upMove > 0 ? upMove : 0;
    const minusDM = downMove > upMove && downMove > 0 ? downMove : 0;
    if (i <= adxLen) {
      smoothTR += tr;
      smoothPlusDM += plusDM;
      smoothMinusDM += minusDM;
    } else {
      smoothTR = smoothTR - smoothTR / adxLen + tr;
      smoothPlusDM = smoothPlusDM - smoothPlusDM / adxLen + plusDM;
      smoothMinusDM = smoothMinusDM - smoothMinusDM / adxLen + minusDM;
    }
    const diPlus = smoothTR !== 0 ? smoothPlusDM / smoothTR * 100 : 0;
    const diMinus = smoothTR !== 0 ? smoothMinusDM / smoothTR * 100 : 0;
    const diSum = diPlus + diMinus;
    const dx = diSum !== 0 ? Math.abs(diPlus - diMinus) / diSum * 100 : 0;
    if (i === 2 * adxLen - 1) {
      adx = dx;
    } else if (i >= 2 * adxLen) {
      adx = (adx * (adxLen - 1) + dx) / adxLen;
    }
    diPlusArr[i] = diPlus;
    diMinusArr[i] = diMinus;
    adxArr[i] = adx;
  }
  const warmup = adxLen;
  const adxWarmup = 2 * adxLen - 1;
  const toPlot = (arr, wu) => arr.map((v, i) => ({ time: bars[i].time, value: i < wu ? NaN : v }));
  const adxPlot = adxArr.map((v, i) => {
    if (i < adxWarmup)
      return { time: bars[i].time, value: NaN };
    const rising = i > adxWarmup && v > adxArr[i - 1];
    const color = rising ? "#26A69A" : "#EF5350";
    return { time: bars[i].time, value: v, color };
  });
  const bgColors = [];
  for (let i = warmup; i < n; i++) {
    const diPlus = diPlusArr[i];
    const diMinus = diMinusArr[i];
    if (diMinus > 60) {
      bgColors.push({ time: bars[i].time, color: "rgba(0,255,0,0.60)" });
    } else if (diPlus > 60) {
      bgColors.push({ time: bars[i].time, color: "rgba(255,165,0,0.80)" });
    } else if (diPlus > diMinus) {
      bgColors.push({ time: bars[i].time, color: "rgba(0,128,0,0.40)" });
    } else if (diMinus > diPlus) {
      bgColors.push({ time: bars[i].time, color: "rgba(255,0,0,0.40)" });
    }
  }
  return {
    metadata: { title: metadata156.title, shorttitle: metadata156.shortTitle, overlay: metadata156.overlay },
    plots: { "plot0": adxPlot, "plot1": toPlot(diPlusArr, warmup), "plot2": toPlot(diMinusArr, warmup) },
    hlines: hlineConfig40.map((h) => ({ value: h.value, options: h.options })),
    bgColors
  };
}
