  const baseHighArr = ta_series_exports.highest(highSeries, baseLen).toArray();
  const baseLowArr = ta_series_exports.lowest(lowSeries, baseLen).toArray();
  const spanBHighArr = ta_series_exports.highest(highSeries, spanBLen).toArray();
  const spanBLowArr = ta_series_exports.lowest(lowSeries, spanBLen).toArray();
  const warmup = Math.max(conversionLen, baseLen, spanBLen);
  const tenkanPlot = [];
  const kijunPlot = [];
  const spanAPlot = [];
  const spanBPlot = [];
  const chikouPlot = [];
  const tenkanArr = new Array(n);
  const kijunArr = new Array(n);
  const spanAValues = new Array(n);
