var metadata176 = {
  title: "CM Gann Swing High Low V2",
  shortTitle: "Gann Swing",
  overlay: true
};
function calculate176(bars, inputs = {}) {
  const { length } = { ...defaultInputs176, ...inputs };
  const n = bars.length;
  const highSeries = new Series(bars, (b) => b.high);
  const lowSeries = new Series(bars, (b) => b.low);
  const highestArr = ta_series_exports.highest(highSeries, length).toArray();
  const lowestArr = ta_series_exports.lowest(lowSeries, length).toArray();
  let swingHigh = NaN;
  let swingLow = NaN;
  const shPlot = [];
  const slPlot = [];
  const warmup = length;
  for (let i = 0; i < n; i++) {
    if (i < warmup) {
      shPlot.push({ time: bars[i].time, value: NaN });
      slPlot.push({ time: bars[i].time, value: NaN });
      continue;
    }
    const hh = highestArr[i];
    const ll = lowestArr[i];
    if (bars[i].high >= hh) {
      swingHigh = hh;
    }
    if (bars[i].low <= ll) {
      swingLow = ll;
    }
    shPlot.push({ time: bars[i].time, value: swingHigh });
    slPlot.push({ time: bars[i].time, value: swingLow });
  }
  const smaHighArr = ta_series_exports.sma(highSeries, length).toArray();
  const smaLowArr = ta_series_exports.sma(lowSeries, length).toArray();
  let hlv = 0;
  const hlvArr = new Array(n).fill(0);
  for (let i = warmup + 1; i < n; i++) {
    const prevSmaHigh = smaHighArr[i - 1];
    const prevSmaLow = smaLowArr[i - 1];
    if (prevSmaHigh != null && bars[i].close > prevSmaHigh) {
      hlv = 1;
    } else if (prevSmaLow != null && bars[i].close < prevSmaLow) {
      hlv = -1;
    }
    hlvArr[i] = hlv;
  }
  const markers = [];
  const barColors = [];
  const bgColors = [];
  const hiArr = shPlot.map((p) => p.value);
  const loArr = slPlot.map((p) => p.value);
  for (let i = warmup + 1; i < n; i++) {
    const hi = hiArr[i];
    const lo = loArr[i];
    const crossAbove = !isNaN(hi) && bars[i].close > hi && bars[i - 1].close < hi;
    const crossBelow = !isNaN(lo) && bars[i].close < lo && bars[i - 1].close > lo;
    if (crossAbove || crossBelow) {
      barColors.push({ time: bars[i].time, color: "#FFFF00" });
    }
    if (crossAbove) {
      bgColors.push({ time: bars[i].time, color: "rgba(0,128,0,0.40)" });
    }
    if (crossBelow) {
      bgColors.push({ time: bars[i].time, color: "rgba(255,0,0,0.40)" });
    }
    if (crossAbove) {
      markers.push({ time: bars[i].time, position: "belowBar", shape: "triangleUp", color: "#00FF00", text: "Cross Up" });
    }
    if (crossBelow) {
      markers.push({ time: bars[i].time, position: "aboveBar", shape: "triangleDown", color: "#FF0000", text: "Cross Down" });
    }
    if (hlvArr[i] === -1) {
      markers.push({ time: bars[i].time, position: "aboveBar", shape: "triangleDown", color: "#FF0000", text: "" });
    } else if (hlvArr[i] === 1) {
      markers.push({ time: bars[i].time, position: "belowBar", shape: "triangleUp", color: "#00FF00", text: "" });
    }
  }
  return {
    metadata: { title: metadata176.title, shorttitle: metadata176.shortTitle, overlay: metadata176.overlay },
    plots: { "plot0": shPlot, "plot1": slPlot },
    markers,
    barColors,
    bgColors
  };
}
