var metadata179 = {
  title: "CM Laguerre PPO PercentileRank",
  shortTitle: "LagPPO",
  overlay: false
};
function calculate179(bars, inputs = {}) {
  const { gamma, pctLen, pctile, wrnPctile } = { ...defaultInputs179, ...inputs };
  const n = bars.length;
  let L0 = 0, L1 = 0, L2 = 0, L3 = 0;
  const lagRsiArr = new Array(n);
  for (let i = 0; i < n; i++) {
    const src = bars[i].close;
    const prevL0 = L0, prevL1 = L1, prevL2 = L2;
    L0 = (1 - gamma) * src + gamma * prevL0;
    L1 = -gamma * L0 + prevL0 + gamma * prevL1;
    L2 = -gamma * L1 + prevL1 + gamma * prevL2;
    L3 = -gamma * L2 + prevL2 + gamma * L3;
    let CU = 0, CD = 0;
    if (L0 >= L1)
      CU += L0 - L1;
    else
      CD += L1 - L0;
    if (L1 >= L2)
      CU += L1 - L2;
    else
      CD += L2 - L1;
    if (L2 >= L3)
      CU += L2 - L3;
    else
      CD += L3 - L2;
    lagRsiArr[i] = CU + CD === 0 ? 0 : CU / (CU + CD) * 100;
  }
  const ppoArr = lagRsiArr.map((v) => v - 50);
  const pctRankArr = new Array(n);
  for (let i = 0; i < n; i++) {
    if (i < pctLen - 1) {
      pctRankArr[i] = NaN;
      continue;
    }
    let count = 0;
    for (let j = i - pctLen + 1; j <= i; j++) {
      if (ppoArr[j] <= ppoArr[i])
        count++;
    }
    pctRankArr[i] = count / pctLen * 100;
  }
  const warmup = pctLen;
  const plot0 = ppoArr.map((v, i) => ({
    time: bars[i].time,
    value: i < 4 ? NaN : v
  }));
  const plot1 = pctRankArr.map((v, i) => {
    if (i < warmup || isNaN(v))
      return { time: bars[i].time, value: NaN };
    const color = v >= pctile ? "#EF5350" : v >= wrnPctile ? "#FF9800" : "#787B86";
    return { time: bars[i].time, value: v, color };
  });
  const plot2 = pctRankArr.map((v, i) => {
    if (i < warmup || isNaN(v))
      return { time: bars[i].time, value: NaN };
    const bVal = -(100 - v);
    const absBVal = Math.abs(bVal);
    const color = absBVal >= pctile ? "#00E676" : absBVal >= wrnPctile ? "#4CAF50" : "#C0C0C0";
    return { time: bars[i].time, value: bVal, color };
  });
  const zeroLine = bars.map((b) => ({ time: b.time, value: 0 }));
  return {
    metadata: { title: metadata179.title, shorttitle: metadata179.shortTitle, overlay: metadata179.overlay },
    plots: { "plot0": plot0, "plot1": plot1, "plot2": plot2, "zeroLine": zeroLine },
    hlines: [
      { value: pctile, options: { color: "#EF5350", linestyle: "solid", title: "Extreme Top" } },
      { value: wrnPctile, options: { color: "#FF9800", linestyle: "solid", title: "Warning Top" } },
      { value: 0, options: { color: "#787B86", linestyle: "solid", title: "Zero" } },
      { value: -wrnPctile, options: { color: "#4CAF50", linestyle: "solid", title: "Warning Bottom" } },
      { value: -pctile, options: { color: "#00E676", linestyle: "solid", title: "Extreme Bottom" } }
    ]
  };
}
