function calculate180(bars, inputs = {}) {
  const { pctP, pblb, pctS, showPinBars, showShavedBars, showInsideBars, showOutsideBars, showGrayBars } = { ...defaultInputs180, ...inputs };
  const barColors = [];
  const plot0 = bars.map((b) => ({ time: b.time, value: NaN }));
  const pctCp = pctP * 0.01;
  const pctCPO = 1 - pctCp;
  const pctCs = pctS * 0.01;
  for (let i = 1; i < bars.length; i++) {
    const curr = bars[i];
    const prev = bars[i - 1];
    const range = curr.high - curr.low;
    let lowestLow = curr.low;
    let highestHigh = curr.high;
    for (let j = 0; j < pblb && i - j >= 0; j++) {
      lowestLow = Math.min(lowestLow, bars[i - j].low);
      highestHigh = Math.max(highestHigh, bars[i - j].high);
    }
    const pBarUp = showPinBars && curr.open > curr.high - range * pctCPO && curr.close > curr.high - range * pctCPO && curr.low <= lowestLow;
    const pBarDn = showPinBars && curr.open < curr.high - range * pctCp && curr.close < curr.high - range * pctCp && curr.high >= highestHigh;
    const sBarUp = showShavedBars && curr.close >= curr.high - range * pctCs;
    const sBarDn = showShavedBars && curr.close <= curr.low + range * pctCs;
    const insideBar = showInsideBars && curr.high <= prev.high && curr.low >= prev.low;
    const outsideBar = showOutsideBars && curr.high > prev.high && curr.low < prev.low;
    let color;
    if (pBarUp)
      color = "#00FF00";
    if (pBarDn)
      color = "#FF0000";
    if (sBarDn)
      color = "#FF00FF";
    if (sBarUp)
      color = "#00FFFF";
    if (insideBar)
      color = "#FFFF00";
    if (outsideBar)
      color = "#FFA500";
    if (color == null && showGrayBars)
      color = "#787B86";
    if (color != null)
      barColors.push({ time: curr.time, color });
  }
  return {
    metadata: { title: metadata180.title, shorttitle: metadata180.shortTitle, overlay: metadata180.overlay },
    plots: { "plot0": plot0 },
    barColors
  };
}
