      const upRangeAggr = bars[i].close > bars[i - 1].close && bars[i].close > bars[i - 1].open;
      const filteredAggr = (prevWvf2 >= prevUb2 || prevWvf2 >= prevRh2) && !(wvf < ub && wvf < rh);
      alert4Arr[i] = upRangeAggr && closeStr && closeLt && filteredAggr ? 1 : 0;
