var metadata201 = {
  title: "Faith Indicator",
  shortTitle: "Faith",
  overlay: false
};
function calculate201(bars, inputs = {}) {
  const { fastLen, slowLen } = { ...defaultInputs201, ...inputs };
  const closeSeries = getSourceSeries(bars, "close");
  const fastArr = ta_series_exports.ema(closeSeries, fastLen).toArray();
  const slowArr = ta_series_exports.ema(closeSeries, slowLen).toArray();
  const faithValues = fastArr.map((v, i) => v - (slowArr[i] ?? 0));
  const faithSeries = new Series(bars, (_b, i) => faithValues[i]);
  const signalArr = ta_series_exports.sma(faithSeries, 9).toArray();
  const warmup = slowLen + 9;
  const faithPlot = faithValues.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const color = v > 0 ? "#2962FF" : "#EF5350";
    return { time: bars[i].time, value: v, color };
  });
  const signalPlot = signalArr.map((v, i) => ({
    time: bars[i].time,
    value: i < warmup || isNaN(v) ? NaN : v
  }));
  const atrArr = ta_series_exports.atr(bars, 30).toArray();
  const fhArr = ta_series_exports.hma(closeSeries, 20).toArray();
  const shArr = ta_series_exports.hma(closeSeries, 25).toArray();
  const bgColors = [];
  for (let i = 1; i < bars.length; i++) {
    const atrVal = atrArr[i] ?? NaN;
    if (isNaN(atrVal))
      continue;
    const istrend = 0.1 * atrVal;
    const fh = fhArr[i] ?? NaN;
    const fhPrev = fhArr[i - 1] ?? NaN;
    const sh = shArr[i] ?? NaN;
    const shPrev = shArr[i - 1] ?? NaN;
    if (isNaN(fh) || isNaN(fhPrev) || isNaN(sh) || isNaN(shPrev))
      continue;
    const fangle = fh - fhPrev;
    const sangle = sh - shPrev;
    const ftrend = fangle > istrend ? 1 : fangle < -istrend ? -1 : 0;
    const strend = sangle > istrend ? 1 : sangle < -istrend ? -1 : 0;
    const hullag = ftrend + strend;
    let color;
    if (hullag === 2)
      color = "rgba(33,150,243,0.15)";
    else if (hullag === 1)
      color = "rgba(38,166,154,0.1)";
    else if (hullag === 0)
      color = "rgba(120,123,134,0.05)";
    else if (hullag === -1)
      color = "rgba(128,0,0,0.1)";
    else
      color = "rgba(239,83,80,0.15)";
    bgColors.push({ time: bars[i].time, color });
  }
  return {
    metadata: { title: metadata201.title, shorttitle: metadata201.shortTitle, overlay: metadata201.overlay },
    plots: { "plot0": faithPlot, "plot1": signalPlot },
    bgColors
  };
}
