    finalH = ta_series_exports.sma(lrHSeries, smoothLen).toArray();
    finalL = ta_series_exports.sma(lrLSeries, smoothLen).toArray();
    finalC = ta_series_exports.sma(lrCSeries, smoothLen).toArray();
