    metadata: { title: metadata226.title, shorttitle: metadata226.shortTitle, overlay: metadata226.overlay },
    plots: { "plot0": plot, "plot1": glowPlot, "osc": oscPlot, "oscTop": oscTopPlot, "oscZero": oscZeroPlot, "oscBot": oscBotPlot },
