var metadata232 = {
  title: "Normalized QQE",
  shortTitle: "nQQE",
  overlay: false
};
function calculate232(bars, inputs = {}) {
  const { rsiLen, smoothFactor, qqeFactor, src, showSignals } = { ...defaultInputs232, ...inputs };
  const n = bars.length;
  const source = getSourceSeries(bars, src);
  const rsi = ta_series_exports.rsi(source, rsiLen);
  const smoothedRsi = ta_series_exports.ema(rsi, smoothFactor);
  const QQEF = smoothedRsi.toArray();
  const TR = new Array(n);
  for (let i = 0; i < n; i++) {
    const cur = QQEF[i] ?? 0;
    const prev = i > 0 ? QQEF[i - 1] ?? 0 : 0;
    TR[i] = Math.abs(cur - prev);
  }
  const wwalpha = 1 / rsiLen;
  const WWMA = new Array(n);
  const ATRRSI = new Array(n);
  WWMA[0] = TR[0];
  ATRRSI[0] = WWMA[0];
  for (let i = 1; i < n; i++) {
    WWMA[i] = wwalpha * TR[i] + (1 - wwalpha) * WWMA[i - 1];
    ATRRSI[i] = wwalpha * WWMA[i] + (1 - wwalpha) * ATRRSI[i - 1];
  }
  const QQES = new Array(n);
  for (let i = 0; i < n; i++) {
    const f = QQEF[i] ?? 0;
    const dar = ATRRSI[i] * qqeFactor;
    const QUP = f + dar;
    const QDN = f - dar;
    if (i === 0) {
      QQES[i] = 0;
    } else {
      const prevS = QQES[i - 1];
      const prevF = QQEF[i - 1] ?? 0;
      if (QUP < prevS) {
        QQES[i] = QUP;
      } else if (f > prevS && prevF < prevS) {
        QQES[i] = QDN;
      } else if (QDN > prevS) {
        QQES[i] = QDN;
      } else if (f < prevS && prevF > prevS) {
        QQES[i] = QUP;
      } else {
        QQES[i] = prevS;
      }
    }
  }
  const warmup = rsiLen + smoothFactor;
  const plot0 = QQEF.map((v, i) => {
    if (v == null || i < warmup)
      return { time: bars[i].time, value: NaN };
    const val = v - 50;
    const color = val > 10 ? "#007002" : val < -10 ? "#FF0000" : "#E8E81A";
    return { time: bars[i].time, value: val, color };
  });
  const plot1 = QQES.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    return { time: bars[i].time, value: v - 50 };
  });
  const markers = [];
  if (showSignals) {
    for (let i = warmup; i < n; i++) {
      const curF = QQEF[i] ?? 0;
      const prevF = QQEF[i - 1] ?? 0;
      const curS = QQES[i];
      const prevS = QQES[i - 1];
      if (prevF <= prevS && curF > curS) {
        markers.push({ time: bars[i].time, position: "belowBar", shape: "labelUp", color: "#008000", text: "Buy" });
      } else if (prevF >= prevS && curF < curS) {
        markers.push({ time: bars[i].time, position: "aboveBar", shape: "labelDown", color: "#FF0000", text: "Sell" });
      }
    }
  }
  return {
    metadata: { title: metadata232.title, shorttitle: metadata232.shortTitle, overlay: metadata232.overlay },
    plots: { "plot0": plot0, "plot1": plot1 },
    hlines: [
      { value: 10, options: { color: "#787B86", linestyle: "dashed", title: "Upper" } },
      { value: -10, options: { color: "#787B86", linestyle: "dashed", title: "Lower" } }
    ],
    markers
  };
}
