function calculate243(bars, inputs = {}) {
  const { lookback } = { ...defaultInputs243, ...inputs };
  const n = bars.length;
  const markers = [];
  const closePlot = bars.map((b) => ({ time: b.time, value: NaN }));
  for (let i = lookback; i < n; i++) {
    const cur = bars[i];
    const isGreen = cur.close > cur.open;
    const isRed = cur.close < cur.open;
    let allRed = true;
    for (let j = 1; j <= lookback; j++) {
      if (bars[i - j].close >= bars[i - j].open) {
        allRed = false;
        break;
      }
    }
    if (allRed && isGreen && cur.close > bars[i - 1].high) {
      markers.push({
        time: cur.time,
        position: "belowBar",
        shape: "arrowUp",
        color: "#26A69A",
        text: "BullRev"
      });
    }
    let allGreen = true;
    for (let j = 1; j <= lookback; j++) {
      if (bars[i - j].close <= bars[i - j].open) {
        allGreen = false;
        break;
      }
    }
    if (allGreen && isRed && cur.close < bars[i - 1].low) {
      markers.push({
        time: cur.time,
        position: "aboveBar",
        shape: "arrowDown",
        color: "#EF5350",
        text: "BearRev"
      });
    }
  }
  const bgColors = [];
  for (const m of markers) {
    if (m.text === "BullRev") {
      bgColors.push({ time: m.time, color: "rgba(0,230,118,0.15)" });
    } else if (m.text === "BearRev") {
      bgColors.push({ time: m.time, color: "rgba(239,83,80,0.15)" });
    }
  }
  return {
    metadata: { title: metadata243.title, shorttitle: metadata243.shortTitle, overlay: metadata243.overlay },
    plots: { "plot0": closePlot },
    markers,
    bgColors
  };
}
