  const phArr = ta_series_exports.pivothigh(highSeries, leftBars, rightBars).toArray();
  const plArr = ta_series_exports.pivotlow(lowSeries, leftBars, rightBars).toArray();
  const warmup = leftBars + rightBars;
  let lastResistance = NaN;
  let lastSupport = NaN;
