  const scalpArr = new Array(n);
  for (let i = 0; i < n; i++) {
    const sig = signalArr[i];
    const ss = ssMAArr[i];
    scalpArr[i] = sig != null && !isNaN(sig) && !isNaN(ss) ? sig - ss : NaN;
  }
  const warmup = halfUp + halfDown;
