var metadata253 = {
  title: "Sell & Buy Rates",
  shortTitle: "SBR",
  overlay: false
};
function calculate253(bars, inputs = {}) {
  const { period } = { ...defaultInputs253, ...inputs };
  const n = bars.length;
  const diffArr = new Array(n);
  for (let i = 0; i < n; i++) {
    const { open, high, low, close, volume: vol } = bars[i];
    const v = vol ?? 0;
    const tw = high - Math.max(open, close);
    const bw = Math.min(open, close) - low;
    const body = Math.abs(close - open);
    const denom = tw + bw + body;
    if (denom === 0) {
      diffArr[i] = 0;
    } else {
      const rateUp = 0.5 * (tw + bw + (open <= close ? 2 * body : 0)) / denom;
      const rateDn = 0.5 * (tw + bw + (open >= close ? 2 * body : 0)) / denom;
      diffArr[i] = v * rateUp - v * rateDn;
    }
  }
  const diffSeries = new Series(bars, (_b, i) => diffArr[i]);
  const rateArr = ta_series_exports.linreg(diffSeries, period, 0).toArray();
  const warmup = period;
  const plot0 = bars.map((b, i) => {
    const rate = rateArr[i];
    if (i < warmup || rate == null || isNaN(rate)) {
      return { time: b.time, value: NaN };
    }
    let isFalling = true;
    let isRising = true;
    for (let j = 0; j < 5; j++) {
      const idx = i - j;
      const prev = idx > 0 ? rateArr[idx - 1] ?? 0 : 0;
      const curr = rateArr[idx] ?? 0;
      if (curr >= prev)
        isFalling = false;
      if (curr <= prev)
        isRising = false;
    }
    let color;
    if (rate > 0) {
      color = isFalling ? "#008000" : "#00FF00";
    } else if (rate < 0) {
      color = isRising ? "#800000" : "#FF0000";
    } else {
      color = "#787B86";
    }
    return { time: b.time, value: rate, color };
  });
  return {
    metadata: { title: metadata253.title, shorttitle: metadata253.shortTitle, overlay: metadata253.overlay },
    plots: { "plot0": plot0 }
  };
}
