  const smoothO = ta_series_exports.sma(haOpenSeries, length).toArray();
  const smoothH = ta_series_exports.sma(haHighSeries, length).toArray();
  const smoothL = ta_series_exports.sma(haLowSeries, length).toArray();
  const smoothC = ta_series_exports.sma(haCloseSeries, length).toArray();
  const warmup = length;
