function calculate259(bars, inputs = {}) {
  const { pivotLen, volumeThresh } = { ...defaultInputs259, ...inputs };
  const n = bars.length;
  const highSeries = new Series(bars, (b) => b.high);
  const lowSeries = new Series(bars, (b) => b.low);
  const volSeries = new Series(bars, (b) => b.volume ?? 0);
  const volEma5 = ta_series_exports.ema(volSeries, 5).toArray();
  const volEma10 = ta_series_exports.ema(volSeries, 10).toArray();
  const volOsc = new Array(n);
  for (let i = 0; i < n; i++) {
    const e5 = volEma5[i] ?? 0;
    const e10 = volEma10[i] ?? 0;
    volOsc[i] = e10 !== 0 ? 100 * (e5 - e10) / e10 : 0;
  }
  const phArr = ta_series_exports.pivothigh(highSeries, pivotLen, pivotLen).toArray();
  const plArr = ta_series_exports.pivotlow(lowSeries, pivotLen, pivotLen).toArray();
  const warmup = pivotLen * 2;
  let lastResistance = NaN;
  let lastSupport = NaN;
  const resistancePlot = [];
  const supportPlot = [];
  const markers = [];
  for (let i = 0; i < n; i++) {
    if (i >= warmup && !isNaN(phArr[i]) && phArr[i] !== 0) {
      lastResistance = phArr[i];
    }
    if (i >= warmup && !isNaN(plArr[i]) && plArr[i] !== 0) {
      lastSupport = plArr[i];
    }
    const volPass = volOsc[i] > volumeThresh;
    if (!isNaN(lastResistance) && bars[i].close > lastResistance) {
      if (i >= warmup && volPass) {
        const bullWick = bars[i].open - bars[i].low > bars[i].close - bars[i].open;
        markers.push({
          time: bars[i].time,
          position: "belowBar",
          shape: "labelUp",
          color: "#26A69A",
          text: bullWick ? "Bull Wick" : "B"
        });
      }
      lastResistance = NaN;
    }
    if (!isNaN(lastSupport) && bars[i].close < lastSupport) {
      if (i >= warmup && volPass) {
        const bearWick = bars[i].open - bars[i].close < bars[i].high - bars[i].open;
        markers.push({
          time: bars[i].time,
          position: "aboveBar",
          shape: "labelDown",
          color: "#EF5350",
          text: bearWick ? "Bear Wick" : "B"
        });
      }
      lastSupport = NaN;
    }
    resistancePlot.push({ time: bars[i].time, value: i < warmup ? NaN : lastResistance });
    supportPlot.push({ time: bars[i].time, value: i < warmup ? NaN : lastSupport });
  }
  return {
    metadata: { title: metadata259.title, shorttitle: metadata259.shortTitle, overlay: metadata259.overlay },
    plots: { "plot0": resistancePlot, "plot1": supportPlot },
    markers
  };
}
