function calculate260(bars, inputs = {}) {
  const { length, mult } = { ...defaultInputs260, ...inputs };
  const n = bars.length;
  const atrSeries = ta_series_exports.atr(bars, length);
  const atrArr = atrSeries.toArray();
  const stopArr = new Array(n);
  const dirArr = new Array(n);
  stopArr[0] = bars[0].close;
  dirArr[0] = 1;
  for (let i = 1; i < n; i++) {
    const close = bars[i].close;
    const atrVal = (atrArr[i] ?? 0) * mult;
    const prevStop = stopArr[i - 1];
    const prevDir = dirArr[i - 1];
    if (prevDir === 1) {
      const newStop = close - atrVal;
      stopArr[i] = Math.max(newStop, prevStop);
      dirArr[i] = close < stopArr[i] ? -1 : 1;
    } else {
      const newStop = close + atrVal;
      stopArr[i] = Math.min(newStop, prevStop);
      dirArr[i] = close > stopArr[i] ? 1 : -1;
    }
  }
  const warmup = length;
  const markers = [];
  for (let i = warmup + 1; i < n; i++) {
    if (dirArr[i] !== dirArr[i - 1]) {
      if (dirArr[i] === 1) {
        markers.push({ time: bars[i].time, position: "belowBar", shape: "labelUp", color: "#26A69A", text: "Buy" });
      } else {
        markers.push({ time: bars[i].time, position: "aboveBar", shape: "labelDown", color: "#EF5350", text: "Sell" });
      }
    }
  }
  const plot0 = stopArr.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const color = dirArr[i] === 1 ? "#26A69A" : "#EF5350";
    return { time: bars[i].time, value: v, color };
  });
  const ohlc4Plot = bars.map((b, i) => ({
    time: b.time,
    value: i < warmup ? NaN : (b.open + b.high + b.low + b.close) / 4
  }));
  const fillColors = bars.map((b, i) => {
    if (i < warmup)
      return "rgba(0,0,0,0)";
    const mid = (b.open + b.high + b.low + b.close) / 4;
    return mid > stopArr[i] ? "rgba(0,128,0,0.12)" : "rgba(255,0,0,0.12)";
  });
  return {
    metadata: { title: metadata260.title, shorttitle: metadata260.shortTitle, overlay: metadata260.overlay },
    plots: { "plot0": plot0, "ohlc4": ohlc4Plot },
    fills: [
      { plot1: "ohlc4", plot2: "plot0", options: { color: "rgba(0,128,0,0.12)" }, colors: fillColors }
    ],
    markers
  };
}
