var metadata264 = {
  title: "Stoch VX3",
  shortTitle: "StochVX3",
  overlay: false
};
function calculate264(bars, inputs = {}) {
  const { len, smooth1, smooth2, smooth3 } = { ...defaultInputs264, ...inputs };
  const n = bars.length;
  const highSeries = new Series(bars, (b) => b.high);
  const lowSeries = new Series(bars, (b) => b.low);
  const hh = ta_series_exports.highest(highSeries, len);
  const ll = ta_series_exports.lowest(lowSeries, len);
  const hhArr = hh.toArray();
  const llArr = ll.toArray();
  const rawK = new Array(n);
  for (let i = 0; i < n; i++) {
    const h = hhArr[i];
    const l = llArr[i];
    if (h == null || l == null || h === l) {
      rawK[i] = i < len ? 0 : 50;
    } else {
      rawK[i] = (bars[i].close - l) / (h - l) * 100;
    }
  }
  const rawKSeries = Series.fromArray(bars, rawK);
  const k2 = ta_series_exports.sma(rawKSeries, smooth1);
  const k3 = ta_series_exports.sma(k2, smooth2);
  const signal = ta_series_exports.sma(k3, smooth3);
  const k3Arr = k3.toArray();
  const sigArr = signal.toArray();
  const warmup = len + smooth1 + smooth2 + smooth3;
  const plot0 = k3Arr.map((v, i) => ({
    time: bars[i].time,
    value: v == null || i < warmup ? NaN : v
  }));
  const plot1 = sigArr.map((v, i) => ({
    time: bars[i].time,
    value: v == null || i < warmup ? NaN : v
  }));
  const markers = [];
  for (let i = warmup + 1; i < n; i++) {
    const k3Now = k3Arr[i] ?? NaN;
    const sigNow = sigArr[i] ?? NaN;
    const k3Prev = k3Arr[i - 1] ?? NaN;
    const sigPrev = sigArr[i - 1] ?? NaN;
    if (isNaN(k3Now) || isNaN(sigNow) || isNaN(k3Prev) || isNaN(sigPrev))
      continue;
    const prevDAbove = sigPrev > k3Prev;
    const currDAbove = sigNow > k3Now;
    if (prevDAbove !== currDAbove) {
      markers.push({
        time: bars[i].time,
        position: sigNow > k3Now ? "aboveBar" : "belowBar",
        shape: "circle",
        color: "#000000",
        text: ""
      });
    }
  }
  const bgColors = [];
  for (let i = warmup; i < n; i++) {
    const k32 = k3Arr[i] ?? NaN;
    const sig = sigArr[i] ?? NaN;
    if (isNaN(k32) || isNaN(sig))
      continue;
    if (k32 < sig) {
      bgColors.push({ time: bars[i].time, color: "rgba(0, 0, 0, 0.20)" });
    } else {
      bgColors.push({ time: bars[i].time, color: "rgba(18, 142, 137, 0.20)" });
    }
  }
  return {
    metadata: { title: metadata264.title, shorttitle: metadata264.shortTitle, overlay: metadata264.overlay },
    plots: { "plot0": plot0, "plot1": plot1 },
    hlines: [
      { value: 80, options: { color: "#787B86", linestyle: "dashed", title: "Overbought" } },
      { value: 20, options: { color: "#787B86", linestyle: "dashed", title: "Oversold" } }
    ],
    // fill between ob/os hlines (Pine: fill(h0, h1, color=purple, transp=100) - fully transparent, decorative)
    fills: [
      { plot1: "overbought", plot2: "oversold", options: { color: "rgba(156, 39, 176, 0.0)" } }
    ],
    markers,
    bgColors
  };
}
