var metadata266 = {
  title: "Super SuperTrend",
  shortTitle: "SST",
  overlay: true
};
function calcSuperTrend(bars, atrArr, mult) {
  const n = bars.length;
  const st = new Array(n);
  const dir = new Array(n);
  for (let i = 0; i < n; i++) {
    const hl2 = (bars[i].high + bars[i].low) / 2;
    const atr = (atrArr[i] ?? 0) * mult;
    const up = hl2 - atr;
    const dn = hl2 + atr;
    if (i === 0) {
      st[i] = up;
      dir[i] = 1;
      continue;
    }
    const prevDir = dir[i - 1];
    const prevSt = st[i - 1];
    const close = bars[i].close;
    const prevClose = bars[i - 1].close;
    const trailUp = prevClose > prevSt && prevDir === 1 ? Math.max(up, prevSt) : up;
    const trailDn = prevClose < prevSt && prevDir === -1 ? Math.min(dn, prevSt) : dn;
    if (prevDir === 1) {
      if (close < trailUp) {
        dir[i] = -1;
        st[i] = trailDn;
      } else {
        dir[i] = 1;
        st[i] = trailUp;
      }
    } else {
      if (close > trailDn) {
        dir[i] = 1;
        st[i] = trailUp;
      } else {
        dir[i] = -1;
        st[i] = trailDn;
      }
    }
  }
  return { st, dir };
}
function calculate266(bars, inputs = {}) {
  const { atrLen, mult1, mult2, mult3 } = { ...defaultInputs266, ...inputs };
  const n = bars.length;
  const atrArr = ta_series_exports.atr(bars, atrLen).toArray();
  const st1 = calcSuperTrend(bars, atrArr, mult1);
  const st2 = calcSuperTrend(bars, atrArr, mult2);
  const st3 = calcSuperTrend(bars, atrArr, mult3);
  const warmup = atrLen;
  const makePlot = (data) => data.st.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const color = data.dir[i] === 1 ? "#26A69A" : "#EF5350";
    return { time: bars[i].time, value: v, color };
  });
  const markers = [];
  const allSTs = [
    { data: st1, upColor: "#FFEB3B", label: "ST1" },
    { data: st2, upColor: "#26A69A", label: "ST2" },
    { data: st3, upColor: "#00E676", label: "ST3" }
  ];
  for (let i = warmup + 1; i < n; i++) {
    for (let si = 0; si < allSTs.length; si++) {
      const { data, upColor, label } = allSTs[si];
      if (data.dir[i] === 1 && data.dir[i - 1] === -1) {
        markers.push({ time: bars[i].time, position: "belowBar", shape: "arrowUp", color: upColor, text: label });
      } else if (data.dir[i] === -1 && data.dir[i - 1] === 1) {
        markers.push({ time: bars[i].time, position: "aboveBar", shape: "arrowDown", color: "#EF5350", text: label });
      }
      const close = bars[i].close;
      const prevClose = bars[i - 1].close;
      const stVal = data.st[i];
      const prevStVal = data.st[i - 1];
      const crossAbove = close > stVal && prevClose <= prevStVal;
      const crossBelow = close < stVal && prevClose >= prevStVal;
      if (si === 0) {
        if (crossAbove)
          markers.push({ time: bars[i].time, position: "belowBar", shape: "square", color: "#FFEB3B", text: `${label}×` });
        if (crossBelow)
          markers.push({ time: bars[i].time, position: "belowBar", shape: "arrowDown", color: "#EF5350", text: `${label}×` });
      } else {
        if (crossAbove)
          markers.push({ time: bars[i].time, position: "belowBar", shape: "arrowUp", color: "#00E676", text: `${label}×` });
        if (crossBelow)
          markers.push({ time: bars[i].time, position: "belowBar", shape: "arrowDown", color: "#EF5350", text: `${label}×` });
      }
    }
  }
  const candles = [];
  for (let i = 0; i < n; i++) {
    candles.push({
      time: bars[i].time,
      open: bars[i].open,
      high: bars[i].high,
      low: bars[i].low,
      close: bars[i].close,
      color: bars[i].open < bars[i].close ? "#26A69A" : "#EF5350",
      wickColor: "#787B86"
    });
  }
  return {
    metadata: { title: metadata266.title, shorttitle: metadata266.shortTitle, overlay: metadata266.overlay },
    plots: {
      "plot0": makePlot(st1),
      "plot1": makePlot(st2),
      "plot2": makePlot(st3)
    },
    markers,
    plotCandles: { candle0: candles }
  };
}
