var metadata274 = {
  title: "Tops/Bottoms",
  shortTitle: "TB",
  overlay: true
};
function calculate274(bars, inputs = {}) {
  const { length, bull, bear } = { ...defaultInputs274, ...inputs };
  const n = bars.length;
  const markers = [];
  const hl2Series = new Series(bars, (b) => (b.high + b.low) / 2);
  const valC = ta_series_exports.sma(hl2Series, length).toArray();
  const atrArr = ta_series_exports.atr(bars, length).toArray();
  const volArr = ta_series_exports.sma(new Series(bars, (_b, i) => atrArr[i] ?? NaN), length).toArray();
  const sqrtLen = Math.sqrt(length);
  const bullLine = [];
  const bearLine = [];
  let prevBull1 = false;
  let prevBear1 = false;
  for (let i = 0; i < n; i++) {
    bullLine.push({ time: bars[i].time, value: bull });
    bearLine.push({ time: bars[i].time, value: bear });
    const v = volArr[i];
    if (v == null || isNaN(v) || v === 0)
      continue;
    const vc = valC[i];
    if (vc == null || isNaN(vc))
      continue;
    const cvi = (bars[i].close - vc) / (v * sqrtLen);
    const bull1 = cvi <= bull;
    const bear1 = cvi >= bear;
    if (prevBull1 && !bull1) {
      markers.push({ time: bars[i].time, position: "belowBar", shape: "circle", color: "#00E676", text: "*" });
    }
    if (prevBear1 && !bear1) {
      markers.push({ time: bars[i].time, position: "aboveBar", shape: "circle", color: "#EF5350", text: "*" });
    }
    prevBull1 = bull1;
    prevBear1 = bear1;
  }
  return {
    metadata: { title: metadata274.title, shorttitle: metadata274.shortTitle, overlay: metadata274.overlay },
    plots: { "plot0": bullLine, "plot1": bearLine },
    markers
  };
}
