var metadata275 = {
  title: "Trend Regularity Adaptive MA",
  shortTitle: "TRAMA",
  overlay: true
};
function calculate275(bars, inputs = {}) {
  const { length, src } = { ...defaultInputs275, ...inputs };
  const srcArr = getSourceSeries(bars, src).toArray();
  const n = bars.length;
  const trama = new Array(n);
  const fastAlpha = 2 / (length + 1);
  for (let i = 0; i < n; i++) {
    const s = srcArr[i] ?? 0;
    if (i < length) {
      trama[i] = s;
      continue;
    }
    let sumAbsChange = 0;
    for (let j = 0; j < length; j++) {
      sumAbsChange += Math.abs((srcArr[i - j] ?? 0) - (srcArr[i - j - 1] ?? 0));
    }
    const avgAbsChange = sumAbsChange / length;
    let trendingCount = 0;
    for (let j = 0; j < length; j++) {
      const absChange = Math.abs((srcArr[i - j] ?? 0) - (srcArr[i - j - 1] ?? 0));
      if (absChange > avgAbsChange)
        trendingCount++;
    }
    const ratio = trendingCount / length;
    const alpha = ratio * fastAlpha;
    trama[i] = alpha * s + (1 - alpha) * trama[i - 1];
  }
  const warmup = length;
  const plot = trama.map((v, i) => {
    if (i < warmup)
      return { time: bars[i].time, value: NaN };
    const prev = i > 0 ? trama[i - 1] : v;
    const color = v > prev ? "#26A69A" : v < prev ? "#EF5350" : "#FFEB3B";
    return { time: bars[i].time, value: v, color };
  });
  return {
    metadata: { title: metadata275.title, shorttitle: metadata275.shortTitle, overlay: metadata275.overlay },
    plots: { "plot0": plot }
  };
}
