  const sqz2On = lowerBB.gt(kcLower2).and(upperBB.lt(kcUpper2));
  const sqz3On = lowerBB.gt(kcLower3).and(upperBB.lt(kcUpper3));
  const sqz1Arr = sqz1On.toArray();
  const sqz2Arr = sqz2On.toArray();
  const sqz3Arr = sqz3On.toArray();
