var metadata286 = {
  title: "Volume-Supported Linear Regression Trend",
  shortTitle: "VSLRT",
  overlay: false
};
function calculate286(bars, inputs = {}) {
  const { src, len1, len2 } = { ...defaultInputs286, ...inputs };
  const n = bars.length;
  const source = getSourceSeries(bars, src);
  const lr1_0 = ta_series_exports.linreg(source, len1, 0).toArray();
  const lr1_1 = ta_series_exports.linreg(source, len1, 1).toArray();
  const lr2_0 = ta_series_exports.linreg(source, len2, 0).toArray();
  const lr2_1 = ta_series_exports.linreg(source, len2, 1).toArray();
  const tw = new Array(n);
  const bw = new Array(n);
  const body = new Array(n);
  for (let i = 0; i < n; i++) {
    tw[i] = bars[i].high - Math.max(bars[i].open, bars[i].close);
    bw[i] = Math.min(bars[i].open, bars[i].close) - bars[i].low;
    body[i] = Math.abs(bars[i].close - bars[i].open);
  }
  function rate(i, cond) {
    const total = tw[i] + bw[i] + body[i];
    if (total === 0)
      return 0.5;
    const r = 0.5 * (tw[i] + bw[i] + (cond ? 2 * body[i] : 0)) / total;
    return isNaN(r) ? 0.5 : r;
  }
  const deltaUp = new Array(n);
  const deltaDown = new Array(n);
  for (let i = 0; i < n; i++) {
    const vol = bars[i].volume ?? 0;
    deltaUp[i] = vol * rate(i, bars[i].open <= bars[i].close);
    deltaDown[i] = vol * rate(i, bars[i].open > bars[i].close);
  }
  const deltaUpSeries = Series.fromArray(bars, deltaUp);
  const deltaDownSeries = Series.fromArray(bars, deltaDown);
  const svUp0 = ta_series_exports.linreg(deltaUpSeries, len1, 0).toArray();
  const svUp1 = ta_series_exports.linreg(deltaUpSeries, len1, 1).toArray();
  const svDn0 = ta_series_exports.linreg(deltaDownSeries, len1, 0).toArray();
  const svDn1 = ta_series_exports.linreg(deltaDownSeries, len1, 1).toArray();
  const lvUp0 = ta_series_exports.linreg(deltaUpSeries, len2, 0).toArray();
  const lvUp1 = ta_series_exports.linreg(deltaUpSeries, len2, 1).toArray();
  const lvDn0 = ta_series_exports.linreg(deltaDownSeries, len2, 0).toArray();
  const lvDn1 = ta_series_exports.linreg(deltaDownSeries, len2, 1).toArray();
  const ccol11 = "#00FF00";
  const ccol12 = "#00BC00";
  const ccol13 = "#00FF006f";
  const ccol21 = "#FF0000";
  const ccol22 = "#BF0000";
  const ccol23 = "#FF00006f";
  const col11 = "#008EFF";
  const col12 = "#006ec5";
  const col13 = "#024478";
  const col21 = "#fd9701";
  const col22 = "#CE7A00";
  const col23 = "#663d00";
  const shortPlot = new Array(n);
  const longPlot = new Array(n);
  for (let i = 0; i < n; i++) {
    if (i < len1 || lr1_0[i] == null || lr1_1[i] == null) {
      shortPlot[i] = { time: bars[i].time, value: NaN };
    } else {
      const slopePrice = lr1_0[i] - lr1_1[i];
      const slopeVolUp = svUp0[i] - svUp1[i];
      const slopeVolDn = svDn0[i] - svDn1[i];
      let colCol;
      if (slopePrice > 0) {
        if (slopeVolUp > 0) {
          colCol = slopeVolUp > slopeVolDn ? ccol11 : ccol12;
        } else {
          colCol = ccol13;
        }
      } else if (slopePrice < 0) {
        if (slopeVolDn > 0) {
          colCol = slopeVolUp < slopeVolDn ? ccol21 : ccol22;
        } else {
          colCol = ccol23;
        }
      } else {
        colCol = "#808080";
      }
      shortPlot[i] = { time: bars[i].time, value: slopePrice * len1, color: colCol };
    }
    if (i < len2 || lr2_0[i] == null || lr2_1[i] == null) {
      longPlot[i] = { time: bars[i].time, value: NaN };
    } else {
      const slopePriceLt = lr2_0[i] - lr2_1[i];
      const slopeVolUpLt = lvUp0[i] - lvUp1[i];
      const slopeVolDnLt = lvDn0[i] - lvDn1[i];
      let lineCol;
      if (slopePriceLt > 0) {
        if (slopeVolUpLt > 0) {
          lineCol = slopeVolUpLt > slopeVolDnLt ? col11 : col12;
        } else {
          lineCol = col13;
        }
      } else if (slopePriceLt < 0) {
        if (slopeVolDnLt > 0) {
          lineCol = slopeVolUpLt < slopeVolDnLt ? col21 : col22;
        } else {
          lineCol = col23;
        }
      } else {
        lineCol = "#808080";
      }
      longPlot[i] = { time: bars[i].time, value: slopePriceLt * len2, color: lineCol };
    }
  }
  return {
    metadata: { title: metadata286.title, shorttitle: metadata286.shortTitle, overlay: metadata286.overlay },
    plots: { plot0: shortPlot, plot1: longPlot }
  };
}
