    const prevSig = i > 0 && i - 1 >= warmup && vwSigArr[i - 1] != null ? vwSigArr[i - 1] : NaN;
    const prevDm = !isNaN(prevVw) && !isNaN(prevSig) ? prevVw - prevSig : dm;
    let color;
