    const ll2dDisp = i - (displacement - 1) >= 0 ? leadLine2Arr[i - (displacement - 1)] ?? 0 : 0;
    const cloudMaxDisp = Math.max(ll1dDisp, ll2dDisp);
    const cloudMinDisp = Math.min(ll1dDisp, ll2dDisp);
