  const n = bars.length;
  const source = getSourceSeries(bars, src);
  const rsiArr = ta_series_exports.rsi(source, rsiLen).toArray();
  const closeArr = source.toArray();
  const warmup = rsiLen + 1;
  const obArr = new Array(n).fill(NaN);
