  for (let i = 0; i < n; i++) {
    if (i < volLen - 1) {
      volSma[i] = 0;
      continue;
    }
    let sum = 0;
    for (let j = i - volLen + 1; j <= i; j++)
      sum += volArr[j];
    volSma[i] = sum / volLen;
  }
  const warmup = Math.max(atrLen, volLen);
  const lookback = 50;
  const adaptedFactor = new Array(n).fill(factor);
  for (let i = warmup; i < n; i++) {
    const curVol = volArr[i];
    const curVolSma = volSma[i];
    if (curVolSma === 0)
      continue;
    const curVolRatio = curVol / curVolSma;
    const distances = [];
    const start = Math.max(warmup, i - lookback);
    for (let j = start; j < i; j++) {
      if (volSma[j] === 0)
        continue;
      const hVolRatio = volArr[j] / volSma[j];
      const dist = Math.abs(curVolRatio - hVolRatio);
      distances.push({ dist, volRatio: hVolRatio });
    }
    distances.sort((a, b) => a.dist - b.dist);
    const kNearest = distances.slice(0, Math.min(k, distances.length));
    if (kNearest.length === 0)
      continue;
    let sumRatio = 0;
    for (const nb of kNearest)
      sumRatio += nb.volRatio;
    const avgRatio = sumRatio / kNearest.length;
    adaptedFactor[i] = factor / Math.max(0.5, Math.min(2, avgRatio));
  }
