function calculate330(bars, inputs = {}) {
  const { length, smoothLen, sensitivity } = { ...defaultInputs330, ...inputs };
  const len = bars.length;
  const typical = new Series(bars, (b) => (b.high + b.low + b.close) / 3);
  const fastEmaArr = ta_series_exports.ema(typical, length).toArray();
  const slowEmaArr = ta_series_exports.ema(typical, length * 2).toArray();
  const volArr = ta_series_exports.stdev(typical, length).toArray();
  const volSeries = Series.fromArray(bars, volArr);
  const smoothVolArr = ta_series_exports.ema(volSeries, smoothLen).toArray();
  const basisArr = new Array(len);
  const upperArr = new Array(len);
  const lowerArr = new Array(len);
  for (let i = 0; i < len; i++) {
    const fast = fastEmaArr[i];
    const slow = slowEmaArr[i];
    const sVol = smoothVolArr[i];
    if (isNaN(fast) || isNaN(slow) || isNaN(sVol)) {
      basisArr[i] = NaN;
      upperArr[i] = NaN;
      lowerArr[i] = NaN;
    } else {
      basisArr[i] = (fast + slow) / 2;
      upperArr[i] = basisArr[i] + sVol * sensitivity;
      lowerArr[i] = basisArr[i] - sVol * sensitivity;
    }
  }
  const trendArr = new Array(len);
  const levelArr = new Array(len);
  for (let i = 0; i < len; i++) {
    if (isNaN(basisArr[i])) {
      trendArr[i] = 0;
      levelArr[i] = NaN;
      continue;
    }
    const close = bars[i].close;
    if (i === 0 || trendArr[i - 1] === 0) {
      trendArr[i] = close > basisArr[i] ? 1 : -1;
      levelArr[i] = trendArr[i] === 1 ? lowerArr[i] : upperArr[i];
      continue;
    }
    const prevTrend2 = trendArr[i - 1];
    if (prevTrend2 === 1) {
      if (close < lowerArr[i]) {
        trendArr[i] = -1;
        levelArr[i] = upperArr[i];
      } else {
        trendArr[i] = 1;
        levelArr[i] = lowerArr[i];
      }
    } else {
      if (close > upperArr[i]) {
        trendArr[i] = 1;
        levelArr[i] = lowerArr[i];
      } else {
        trendArr[i] = -1;
        levelArr[i] = upperArr[i];
      }
    }
  }
  const warmup = length * 2 + smoothLen;
  const plot0 = basisArr.map((v, i) => {
    if (i < warmup || isNaN(v))
      return { time: bars[i].time, value: NaN };
    const color = trendArr[i] === 1 ? "#00ffaa" : "#ff0000";
    return { time: bars[i].time, value: v, color };
  });
  const plot1 = levelArr.map((v, i) => {
    if (i < warmup || isNaN(v))
      return { time: bars[i].time, value: NaN };
    const color = bars[i].close > v ? "#00ffaa" : "#ff0000";
    return { time: bars[i].time, value: v, color };
  });
  const barColors = [];
  for (let i = warmup; i < len; i++) {
    if (trendArr[i] !== 0) {
      barColors.push({
        time: bars[i].time,
        color: trendArr[i] === 1 ? "rgba(0, 255, 170, 0.85)" : "rgba(255, 0, 0, 0.85)"
      });
    }
  }
  const bgColors = [];
  let intensity = 0;
  let prevTrend = 0;
  for (let i = warmup; i < len; i++) {
    if (trendArr[i] !== prevTrend) {
      intensity = 0;
      prevTrend = trendArr[i];
    }
    intensity = Math.min(intensity + 1, 20);
    const alpha = 0.05 + intensity / 20 * 0.15;
    if (trendArr[i] === 1) {
      bgColors.push({ time: bars[i].time, color: `rgba(0, 255, 170, ${alpha.toFixed(2)})` });
    } else if (trendArr[i] === -1) {
      bgColors.push({ time: bars[i].time, color: `rgba(255, 0, 0, ${alpha.toFixed(2)})` });
    }
  }
  const fillColors = [];
  for (let i = 0; i < len; i++) {
    if (i < warmup || isNaN(basisArr[i])) {
      fillColors.push("transparent");
    } else {
      fillColors.push(trendArr[i] === 1 ? "rgba(0, 255, 170, 0.25)" : "rgba(255, 0, 0, 0.25)");
    }
  }
  const labels = [];
  for (let i = warmup + 1; i < len; i++) {
    if (isNaN(levelArr[i]) || isNaN(levelArr[i - 1]))
      continue;
    const prevClose = bars[i - 1].close;
    const curClose = bars[i].close;
    const prevLevel = levelArr[i - 1];
    const curLevel = levelArr[i];
    if (prevClose >= prevLevel && curClose < curLevel) {
      labels.push({
        time: bars[i].time,
        price: curLevel,
        text: "𝑺",
        // "𝑺"
        color: "#ff0000",
        textColor: "#FFFFFF",
        style: "label_down"
      });
    }
    if (prevClose <= prevLevel && curClose > curLevel) {
      labels.push({
        time: bars[i].time,
        price: curLevel,
        text: "𝑱",
        // "𝑳"
        color: "#00ffaa",
        textColor: "#000000",
        style: "label_up"
      });
    }
  }
  return {
    metadata: { title: metadata330.title, shorttitle: metadata330.shortTitle, overlay: metadata330.overlay },
    plots: { "plot0": plot0, "plot1": plot1 },
    // fill between basis (plot0) and level (plot1) colored by trend
    fills: [
      { plot1: "plot0", plot2: "plot1", options: { color: "rgba(0, 255, 170, 0.25)" }, colors: fillColors }
    ],
    barColors,
    bgColors,
    labels
  };
}
