function calculate344(bars, inputs = {}) {
  const cfg = { ...defaultInputs344, ...inputs };
  const n = bars.length;
  const mult = cfg.factor;
  const slopeVal = cfg.slope * mult;
  const atrArr = ta_series_exports.atr(bars, 200).toArray();
  const warmup = 200;
  let pcAvg = bars.length > 0 ? bars[0].close : 0;
  let os = 1;
  let holdAtr = 0;
  const pcAvgArr = new Array(n);
  const r2Arr = new Array(n);
  const r1Arr = new Array(n);
  const s1Arr = new Array(n);
  const s2Arr = new Array(n);
  for (let i = 0; i < n; i++) {
    const close = bars[i].close;
    const atr = (atrArr[i] ?? 0) * mult;
    if (Math.abs(close - pcAvg) > atr) {
      pcAvg = close;
    } else {
      pcAvg = pcAvg + os * holdAtr / (slopeVal === 0 ? 1 : slopeVal);
    }
    if (pcAvg === close) {
      holdAtr = atr / 2;
    }
    if (i > 0) {
      if (pcAvg > pcAvgArr[i - 1])
        os = 1;
      else if (pcAvg < pcAvgArr[i - 1])
        os = -1;
    }
    pcAvgArr[i] = pcAvg;
    r2Arr[i] = pcAvg + holdAtr;
    r1Arr[i] = pcAvg + holdAtr / 2;
    s1Arr[i] = pcAvg - holdAtr / 2;
    s2Arr[i] = pcAvg - holdAtr;
  }
  const makePlot = (arr) => arr.map((v, i) => ({
    time: bars[i].time,
    // Pine: close == pc_avg ? na : value (hide when resetting)
    value: i < warmup ? NaN : bars[i].close === pcAvgArr[i] ? NaN : v
  }));
  const fillColors = pcAvgArr.map((avg, i) => {
    if (i < warmup || bars[i].close === avg)
      return "transparent";
    return bars[i].close > avg ? "rgba(8,153,129,0.20)" : "rgba(242,54,69,0.20)";
  });
  return {
    metadata: { title: metadata344.title, shorttitle: metadata344.shortTitle, overlay: metadata344.overlay },
    plots: {
      r2: makePlot(r2Arr),
      r1: makePlot(r1Arr),
      avg: makePlot(pcAvgArr),
      s1: makePlot(s1Arr),
      s2: makePlot(s2Arr)
    },
    fills: [
      { plot1: "r2", plot2: "s2", options: { color: "rgba(8,153,129,0.20)" }, colors: fillColors }
    ]
  };
}
