function lazyLine(data, length) {
  if (length <= 2)
    return data;
  const w2 = Math.round(length / 3);
  const w1 = Math.round((length - w2) / 2);
  const w3 = Math.floor((length - w2) / 2);
  const L1 = ta_series_exports.wma(data, Math.max(1, w1));
  const L2 = ta_series_exports.wma(L1, Math.max(1, w2));
  return ta_series_exports.wma(L2, Math.max(1, w3));
}
function getMA(source, length, type) {
  switch (type) {
    case "SMA":
      return ta_series_exports.sma(source, length);
    case "EMA":
      return ta_series_exports.ema(source, length);
    case "WMA":
      return ta_series_exports.wma(source, length);
    case "HMA":
      return ta_series_exports.hma(source, length);
    default:
      return lazyLine(source, length);
  }
}
function calculate346(bars, inputs = {}) {
  const { fastLength, fastType, slowLength, slowType, slowDelay, filterLength, filterType } = { ...defaultInputs346, ...inputs };
  const n = bars.length;
  const closeSeries = new Series(bars, (b) => b.close);
  const fast = getMA(closeSeries, fastLength, fastType);
  const slow = getMA(closeSeries, slowLength, slowType);
  const filter = getMA(closeSeries, filterLength, filterType);
  const fastArr = fast.toArray();
  const slowArr = slow.toArray();
  const filterArr = filter.toArray();
  const fastM = new Array(n);
  const slowM = new Array(n);
  for (let i = 0; i < n; i++) {
    fastM[i] = (fastArr[i] ?? NaN) - (filterArr[i] ?? NaN);
    slowM[i] = (slowArr[i] ?? NaN) - (filterArr[i] ?? NaN);
  }
  const slowMSeries = Series.fromArray(bars, slowM);
  const relMArr = ta_series_exports.wma(slowMSeries, slowDelay).toArray();
  const warmup = filterLength;
  const candles = [];
  for (let i = 0; i < n; i++) {
    if (i < warmup || relMArr[i] == null || isNaN(relMArr[i]) || isNaN(fastM[i])) {
      candles.push({ time: bars[i].time, open: NaN, high: NaN, low: NaN, close: NaN });
      continue;
    }
    const o = relMArr[i];
    const c = fastM[i];
    const h = Math.max(o, c);
    const l = Math.min(o, c);
    const prevC = i > 0 ? fastM[i - 1] : c;
    const rising = c - prevC > 0;
    let barColor;
    let borderColor;
    if (c > o && rising) {
      barColor = "#11ff20";
      borderColor = "#1b5e20";
    } else if (c < o && !rising) {
      barColor = "#ff1111";
      borderColor = "#981919";
    } else {
      barColor = "#ffffff";
      borderColor = "#9598a1";
    }
    candles.push({
      time: bars[i].time,
      open: o,
      high: h,
      low: l,
      close: c,
      color: barColor,
      borderColor,
      wickColor: barColor
    });
  }
  return {
    metadata: { title: metadata346.title, shorttitle: metadata346.shortTitle, overlay: metadata346.overlay },
    plots: {},
    plotCandles: { mobars: candles },
    hlines: [
      { value: 0, options: { color: "#2962FF", linestyle: "solid", title: "Zero Line" } }
    ]
  };
}
