    const r = bar.high - bar.low;
    plot0.push({ time: t, value: NaN });
    const isBullBar = bar.close > bar.open;
    barColors.push({ time: t, color: isBullBar ? bull : bear });
    if (displayType !== "Candle" && r > 0 && i >= atrLen) {
      lines.push({
        time1: t,
        price1: bar.high,
        time2: t,
        price2: bar.low,
        color: isBullBar ? bull : bear,
        width: 3
      });
    }
