function computeMA2(bars, src, len, type) {
  const n = src.length;
  const srcSeries = new Series(bars, (_, i) => src[i]);
  switch (type) {
    case "SMA":
      return ta_series_exports.sma(srcSeries, len).toArray().map((v) => v ?? NaN);
    case "EMA":
      return ta_series_exports.ema(srcSeries, len).toArray().map((v) => v ?? NaN);
    case "WMA":
      return ta_series_exports.wma(srcSeries, len).toArray().map((v) => v ?? NaN);
    case "DEMA": {
      const e1 = ta_series_exports.ema(srcSeries, len).toArray();
      const e1Series = new Series(bars, (_, i) => e1[i] ?? NaN);
      const e2 = ta_series_exports.ema(e1Series, len).toArray();
      return e1.map((v, i) => {
        const v1 = v ?? NaN;
        const v2 = e2[i] ?? NaN;
        return 2 * v1 - v2;
      });
    }
    case "Smoothed_MA": {
      const smaArr = ta_series_exports.sma(srcSeries, len).toArray();
      const result = new Array(n).fill(NaN);
      for (let i = 0; i < n; i++) {
        if (isNaN(result[i - 1] ?? NaN)) {
          result[i] = smaArr[i] ?? NaN;
        } else {
          result[i] = (result[i - 1] * (len - 1) + src[i]) / len;
        }
      }
      return result;
    }
    case "Zero_Lag": {
      const lag = Math.floor((len - 1) / 2);
      const d = new Array(n);
      for (let i = 0; i < n; i++) {
        const prev = i >= lag ? src[i - lag] : NaN;
        d[i] = src[i] + (src[i] - prev);
      }
      const dSeries = new Series(bars, (_, i) => d[i]);
      return ta_series_exports.ema(dSeries, len).toArray().map((v) => v ?? NaN);
    }
    case "Wilders": {
      const result = new Array(n).fill(NaN);
      for (let i = 0; i < n; i++) {
        if (isNaN(src[i]))
          continue;
        if (isNaN(result[i - 1] ?? NaN)) {
          if (i >= len - 1) {
            let sum = 0;
            for (let j = i - len + 1; j <= i; j++)
              sum += src[j];
            result[i] = sum / len;
          }
        } else {
          result[i] = (src[i] + result[i - 1] * (len - 1)) / len;
        }
      }
      return result;
    }
    case "Super_Smoother": {
      const pi = Math.PI;
      const a1 = Math.exp(-1.414 * pi / len);
      const b1 = 2 * a1 * Math.cos(1.414 * pi / len);
      const c2 = b1;
      const c3 = -(a1 * a1);
      const c1 = 1 - c2 - c3;
      const result = new Array(n).fill(NaN);
      for (let i = 0; i < n; i++) {
        if (isNaN(src[i]))
          continue;
        if (i < 2 || isNaN(result[i - 1]) || isNaN(result[i - 2])) {
          result[i] = src[i];
        } else {
          result[i] = c1 * (src[i] + src[i - 1]) / 2 + c2 * result[i - 1] + c3 * result[i - 2];
        }
      }
      return result;
    }
    case "McGuinley": {
      const result = new Array(n).fill(NaN);
      for (let i = 0; i < n; i++) {
        if (isNaN(src[i]))
          continue;
        if (isNaN(result[i - 1] ?? NaN)) {
          result[i] = src[i];
        } else {
          const prev = result[i - 1];
          const ratio = src[i] / prev;
          result[i] = prev + (src[i] - prev) / (len * Math.pow(ratio, 4));
        }
      }
      return result;
    }
    default:
      return ta_series_exports.ema(srcSeries, len).toArray().map((v) => v ?? NaN);
  }
}
