      prevZZ1 = zigzag.length >= 2 ? zigzag[1] : NaN;
      prevZZ2 = zigzag.length >= 3 ? zigzag[2] : NaN;
      prevZZ3 = zigzag.length >= 4 ? zigzag[3] : NaN;
