  const n = bars.length;
  const highSeries = new Series(bars, (b) => b.high);
  const lowSeries = new Series(bars, (b) => b.low);
  const phArr = ta_series_exports.pivothigh(highSeries, prd, prd).toArray();
  const plArr = ta_series_exports.pivotlow(lowSeries, prd, prd).toArray();
  const closeArr = bars.map((b) => b.close);
  const tval = [];
